import{_ as a,o as t,c as n,O as s}from"./chunks/framework.92cbe775.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/product/customer-flow.md","filePath":"en/product/customer-flow.md","lastUpdated":1776068451000}'),i={name:"en/product/customer-flow.md"};function r(l,e,d,o,c,p){return t(),n("div",null,e[0]||(e[0]=[s('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Customer Flow &amp; Delivery</p><h1>Customer Flow / Delivery</h1><div class="brand-hero__panel"><span class="brand-pill">Practical View</span><strong>Delivery is not finished when a page goes live. Delivery is only stable when the customer can keep adding, updating, and using capabilities safely afterward.</strong><p>The customer path, the delivery boundary, and the update mechanism all need to be defined clearly if the project is going to run stably.</p></div><p class="brand-lead"> The most important questions ExecGov needs to explain first are <strong>what the customer receives, how the customer uses it, and how the platform delivers it.</strong> The script hot-update flow already has its own page. This page focuses on the standard team edition and enterprise delivery stage and explains what the real delivery path looks like end to end. </p><div class="brand-chip-list"><span class="brand-chip">Standard team / enterprise delivery</span><span class="brand-chip">Manual run + AI recommendation</span><span class="brand-chip">Delivery package</span><span class="brand-chip">Tenant isolation</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="../contact.html#lead-form">Discuss team / enterprise delivery</a><a class="cta-button" href="./hot-update.html">View hot-update notes</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECGOV // CUSTOMER FLOW</span><span>DOC 08</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">deliveryPack</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;tenant_space&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;dedicated_url&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;account&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;authorized_skills&#39;</span><span class="matrix-panel__punct">]</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">userPath</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;manual_trigger&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;ai_recommend&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;confirm&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;result&#39;</span><span class="matrix-panel__punct">]</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">updateFlow</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;review&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;sync&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;register&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;authorize&#39;</span><span class="matrix-panel__punct">]</span></span></div><div class="matrix-panel__callout">GO-LIVE IS THE START OF OPERATIONS</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">delivery</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">ready</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">update</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">controlled</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">tenant</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">isolated</span></span></div></div></div></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Delivery Package</p><h2>What a customer receives in formal team or enterprise delivery</h2><ul class="brand-list"><li>An isolated tenant</li><li>A dedicated access URL</li><li>A set of customer-specific script capabilities</li><li>Platform accounts and baseline permissions</li><li>Customer usage notes and script hot-update notes</li></ul><p>The point is not just to hand over a backend account. The point is to deliver an isolated AI execution space that can run, update, and continue to expand for the customer.</p></article><article class="brand-card"><p class="brand-kicker">Boundary</p><h2>How delivery boundaries are defined right now</h2><ul class="brand-list"><li>Both the formal team edition and enterprise delivery are tenant-isolated, with the access entry bound to the tenant by Host</li><li>Customers use only their own authorized capabilities inside their own tenant space</li><li>The platform prioritizes secure isolation and stable execution first</li><li>In standard SaaS, the shared element is the frontend release rhythm, not tenant data or permissions</li><li>The default scope does not include a public third-party capability marketplace, tenant self-publishing, or approval-free high-risk automation</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Shared SaaS Boundary</p><h2>How to understand the standard shared-SaaS tenant model</h2><div class="brand-grid brand-grid--two"><article class="brand-card brand-card--nested"><h3>What is already true today</h3><p>Standard SaaS customers can already enter through the shared-tenant frontend. Runtime isolation still happens through Host-to-schema binding, so each customer still sees its own menu, account space, capabilities, and data boundary.</p></article><article class="brand-card brand-card--nested"><h3>What should not be misunderstood</h3><p>This does not mean every customer owns a cloned frontend codebase. What is shared is the formal frontend package and release rhythm. Heavier customer-specific frontend work, branding, and deep customization still require formal iteration or separate delivery.</p></article></div></section><section class="brand-card"><p class="brand-kicker">End To End</p><h2>How one chain runs from scenario confirmation to hot-update activation</h2><div class="brand-grid brand-grid--four"><article class="brand-card brand-card--nested"><h3>01. Clarify the customer scenario</h3><p>Confirm the business problem, the capabilities that need to be delivered, which tasks need AI recommendation, and which still need manual confirmation.</p></article><article class="brand-card brand-card--nested"><h3>02. Open the tenant and the entry</h3><p>The platform opens a dedicated tenant, access URL, initial account, and permission boundary for the project.</p></article><article class="brand-card brand-card--nested"><h3>03. Onboard the first capability batch</h3><p>The platform completes review, sync, registration, and authorization so the customer can see the first capability set immediately after login.</p></article><article class="brand-card brand-card--nested"><h3>04. The customer starts using it</h3><p>The customer either triggers capabilities manually through the page or describes the request in the intelligent brain, where the platform recommends capabilities inside the current tenant.</p></article><article class="brand-card brand-card--nested"><h3>05. Continuous feedback during operation</h3><p>Based on results, announcements, and actual usage, the customer asks for script updates or new capabilities.</p></article><article class="brand-card brand-card--nested"><h3>06. Submit through the hot-update flow</h3><p>The customer supplements the script directory, README, tenant attribution, whether AI may call it, and whether manual confirmation is required.</p></article><article class="brand-card brand-card--nested"><h3>07. The platform performs the governance actions</h3><p>The platform continues with review, sync, registration, version recording, authorization binding, and permission verification without redeploying the whole platform.</p></article><article class="brand-card brand-card--nested"><h3>08. It takes effect formally inside the owning tenant</h3><p>The updated capability becomes visible only inside the owning tenant. Other tenants do not gain visibility or execution rights, and AI recommendations do not cross tenants.</p></article></div></section><section class="brand-card"><p class="brand-kicker">Delivery Checklist</p><h2>How a delivery checklist can be aligned</h2><table><thead><tr><th>Delivery item</th><th>What the customer gets / sees</th><th>What the platform owns</th><th>Notes</th></tr></thead><tbody><tr><td>Dedicated tenant</td><td>Their own tenant space</td><td>Create the tenant and isolate data plus permission boundaries</td><td>One customer, one tenant</td></tr><tr><td>Dedicated URL</td><td>Their own access entry</td><td>Open the access address and login entry</td><td>This is true for both single-tenant delivery and shared SaaS. Shared SaaS currently binds tenants by Host.</td></tr><tr><td>Login account</td><td>Account, initial password, or initialization method</td><td>Initialize the account and baseline permissions</td><td>Permissions are delivered per project</td></tr><tr><td>Customer-specific capabilities</td><td>The capability list visible inside the current tenant</td><td>Review, registration, and authorization binding</td><td>Not shared across tenants</td></tr><tr><td>Announcements and result viewing</td><td>Announcement entries, execution results, and related outputs</td><td>Announcement publishing, result display, and download-entry exposure</td><td>Always controlled by current tenant visibility rules</td></tr><tr><td>Hot-update notes</td><td>The onboarding process for new or updated scripts</td><td>Directory rules, review flow, and authorization rules</td><td>Review remains platform-controlled by default</td></tr><tr><td>Menu extension</td><td>Entries for existing pages, external links, or iframes</td><td>Configure the menu, validate boundaries, and control release rhythm</td><td>New formal frontend pages still require development, packaging, and deployment</td></tr><tr><td>Local hybrid execution</td><td>CLI / Agent is added when needed</td><td>Bridge capability is added according to project needs</td><td>Not included in every standard delivery by default. See the <a href="./cli.html">CLI Guide</a>.</td></tr></tbody></table></section><section class="brand-card"><p class="brand-kicker">Path Matching</p><h2>Which path fits which demand best</h2><table><thead><tr><th>Current demand</th><th>Better-fit path</th><th>Current state</th><th>Notes</th></tr></thead><tbody><tr><td>You want to feel the real execution chain first</td><td>Public experience page + signup / login</td><td>Available now</td><td>Useful for feeling AI recommendation, confirmation, execution, and result return before deciding whether formal delivery is needed.</td></tr><tr><td>You only want to keep onboarding scripts personally and have not entered multi-user collaboration yet</td><td>Start with local script-slot expansion under <a href="./personal-billing-membership.html">Billing &amp; Membership</a></td><td>Available now</td><td>This is personal-space expansion, not the main formal team / enterprise delivery path of this page.</td></tr><tr><td>You already need multi-user collaboration, but the demand is still relatively standard</td><td>Standard shared-SaaS tenant path</td><td>The shared-tenant skeleton already exists and is still being tightened</td><td>This is a better fit for standard capability and lighter collaboration. Runtime still binds each tenant by Host and does not share data or permissions.</td></tr><tr><td>You already have a real customer and need formal go-live delivery</td><td>Single-tenant delivery</td><td>Mainline today</td><td>Best for customers that need stronger isolation, dedicated pages, custom branding, or formal acceptance.</td></tr><tr><td>You need to operate multiple customers in one platform</td><td>Platform governance + single-tenant delivery</td><td>Composable now</td><td><code>public</code> owns governance while each customer tenant stays isolated and announcements, templates, logs, and ledgers are centrally managed.</td></tr><tr><td>The script depends on local environments or intranet data</td><td>Hybrid execution + the <a href="./cli.html">CLI / Agent path</a></td><td>Partially established now</td><td>The control plane stays on the platform side while the execution side is integrated per project instead of exposing the intranet path directly to the browser.</td></tr><tr><td>You want to buy a standard team product directly</td><td>Evaluate the shared-SaaS tenant path first, then check whether it is sufficient through <a href="./editions.html">Editions</a></td><td>The shared-tenant skeleton already exists and is still being tightened</td><td>If the need is mostly standard capability and light collaboration, shared SaaS should be tested first. If the work needs dedicated pages, branding, or stronger isolation, then move into single-tenant delivery or private deployment.</td></tr></tbody></table></section><section class="brand-card"><p class="brand-kicker">Menu Rules</p><h2>Menu customization boundaries</h2><ul class="brand-list"><li>Existing formal pages can be attached through the database menu</li><li>External links and iframe entries can also enter the menu system</li><li>If the customer needs a new page that does not exist in the current frontend package, that still requires formal frontend development, packaging, and deployment</li><li>Shared SaaS does not let tenants upload arbitrary Vue / JS code and turn it into a formal product page</li></ul></section><section class="brand-card"><p class="brand-kicker">Customer Usage</p><h2>How customers use the platform today</h2><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><h3>1. Log in to their own URL</h3><p>After delivery, the customer receives an access URL, login account, and either an initial password or an initialization method. After login, they enter their own isolated tenant space.</p></article><article class="brand-card brand-card--nested"><h3>2. See their capabilities, not raw source</h3><p>Customers see the list of capabilities authorized inside the current tenant rather than raw script paths or another customer&#39;s data.</p></article><article class="brand-card brand-card--nested"><h3>3. Choose manual execution or AI-assisted execution</h3><p>Customers can trigger a capability directly, or they can describe a request in the intelligent brain and let the platform recommend a capability inside the current tenant and permission scope.</p></article></div></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Manual Run</p><h2>Manual execution flow</h2><ol class="brand-list"><li>Log in to the platform</li><li>Open the visible capability list</li><li>Select the target capability</li><li>Fill in the required input</li><li>Submit execution</li><li>Inspect the execution result or the resulting artifact</li></ol></article><article class="brand-card"><p class="brand-kicker">AI Assisted</p><h2>AI-assisted execution flow</h2><ol class="brand-list"><li>Describe the request in the intelligent-brain page</li><li>The platform recommends available capabilities inside the current tenant and permission boundary</li><li>If confirmation is required, manual confirmation happens first</li><li>After confirmation, the platform executes the capability</li><li>The page returns the result</li></ol></article></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Notice &amp; Result</p><h2>What else customers can see</h2><ul class="brand-list"><li>Execution-result summaries, output artifacts, and related output information</li><li>Platform announcements and tenant announcements</li><li>Announcement title, source, publisher, publish time, and body</li><li>Customer-side entries already opened today, including file upload and result download</li></ul></article><article class="brand-card"><p class="brand-kicker">Safety Rule</p><h2>Boundaries customers should notice while using it</h2><ul class="brand-list"><li>Customers only see the capabilities authorized inside their own tenant</li><li>They do not see another customer&#39;s scripts or execution records</li><li>AI does not recommend another customer&#39;s capability</li><li>Some higher-risk capabilities still require manual confirmation before execution</li></ul></article></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Local Execution</p><h2>What if the script depends on a local environment or intranet resource</h2><p>These scenarios are usually not handled by exposing an intranet directory directly to a web page. They are handled through the CLI / Agent bridge. The platform keeps the entry, planning, permission, and audit logic, while the local environment handles execution.</p><p><a href="./cli.html">View the CLI Guide</a></p></article><article class="brand-card"><p class="brand-kicker">Who Owns What</p><h2>Who owns what after go-live</h2><ul class="brand-list"><li>The customer owns the script, the README, the scenario description, and the update request</li><li>The platform owns review, sync, registration, authorization, and permission verification</li><li>The customer owns confirming whether the output fits the business need</li><li>The platform owns tenant isolation, execution safety, and capability-governance logic</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Hot Update</p><h2>Hot-update notes now live on their own page</h2><p>The details of how a customer prepares a script directory, supplements submission information, enters review, completes registration, and goes live inside the current tenant have been split into a dedicated page so presales, delivery, and training can quote it separately.</p><div class="brand-link-grid"><a class="brand-link-card" href="./hot-update.html"><span>Hot Update</span><strong>Hot Update</strong><p>Read directory preparation, review and sync, registration and authorization, and tenant-boundary activation in one place.</p></a><a class="brand-link-card" href="./file-results.html"><span>Files</span><strong>Files &amp; Results</strong><p>Best for file-driven tasks where the user uploads input files, processes reports, and downloads result artifacts.</p></a><a class="brand-link-card" href="./onboarding-checklist.html"><span>Checklist</span><strong>Onboarding Checklist</strong><p>Best for presales and implementation conversations that need the script directory, README, examples, and boundary information aligned in one pass.</p></a></div></section><section class="brand-card"><p class="brand-kicker">Related Reading</p><h2>For delivery, file flow, and onboarding preparation, continue with these three pages</h2><div class="brand-link-grid brand-link-grid--three"><a class="brand-link-card" href="./file-results.html"><span>Files</span><strong>Files &amp; Results</strong><p>Best for tasks that require file upload, report processing, or downloadable output artifacts.</p></a><a class="brand-link-card" href="./deliverables.html"><span>Deliverables</span><strong>Deliverables</strong><p>Best when you need to define exactly which URL, account, instructions, and result entry the customer will finally receive.</p></a><a class="brand-link-card" href="./onboarding-checklist.html"><span>Checklist</span><strong>Onboarding Checklist</strong><p>Best for presales and implementation conversations that need the script directory, README, example files, and risk boundaries aligned in one pass.</p></a></div></section><section class="brand-card"><p class="brand-kicker">FAQ</p><h2>The customer and presales questions that come up most often</h2><div class="brand-grid brand-grid--two"><article class="brand-card brand-card--nested"><h3>Do we have to begin with private deployment</h3><p>Not necessarily. The better first step is to look at the data boundary, customer scale, and execution location, then decide between single-tenant delivery, platform-governance composition, or a hybrid-execution route.</p></article><article class="brand-card brand-card--nested"><h3>Will a hot update affect other customers</h3><p>No. Even after the update lands, the script is only registered and authorized inside the owning tenant. Other tenants do not automatically gain visibility or execution rights.</p></article><article class="brand-card brand-card--nested"><h3>Can customers upload scripts and go live directly</h3><p>Not in the default <code>1.0</code> path. The platform keeps review, registration, authorization, and permission verification in place instead of allowing direct production publishing.</p></article><article class="brand-card brand-card--nested"><h3>Can AI recommend another customer&#39;s capabilities</h3><p>No. Recommendation scope is constrained by both tenant and permission boundaries. AI does not recommend another customer&#39;s scripts or capabilities across tenants.</p></article><article class="brand-card brand-card--nested"><h3>Can local scripts and intranet resources connect into the platform</h3><p>Yes, but normally not by exposing local paths to the browser. The normal route is to use <code>execgov-cli</code> and the future Agent line as the local execution bridge.</p></article><article class="brand-card brand-card--nested"><h3>Are the free path and enterprise delivery two unrelated systems</h3><p>No. They share the same trusted-execution foundation. What changes is the entry semantics, delivery boundary, and target user group.</p></article></div></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Acceptance</p><h2>What formal customer acceptance usually checks</h2><ul class="brand-list"><li>Can the customer log in through their own URL</li><li>Can the customer see only their own capabilities</li><li>Can the customer execute their own capabilities</li><li>Can the customer view execution results or result files</li><li>Can the customer continue updating scripts through the formal process</li></ul></article><article class="brand-card"><p class="brand-kicker">One Sentence</p><h2>One-sentence summary of the delivery mainline</h2><p>ExecGov delivers more than a login entry. It delivers an isolated AI execution space that can run, update, and continue to expand for the customer. Hot updates are not platform redeploys, but formal review, registration, and authorization steps that take effect inside the current tenant.</p></article></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Read</p><h2>Continue with platform capabilities, or move directly into a delivery conversation</h2><p class="brand-lead">Continue with Capabilities, Deployment, and Architecture. If you already have real script capabilities and a real customer scenario, bring the directory structure and requirements directly into the conversation.</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="./capabilities.html"><span>Capability</span><strong>Capabilities</strong></a><a class="brand-link-card" href="./file-results.html"><span>Files</span><strong>Files &amp; Results</strong></a><a class="brand-link-card" href="./deliverables.html"><span>Deliverables</span><strong>Deliverables</strong></a><a class="brand-link-card" href="./deployment.html"><span>Deployment</span><strong>Deployment</strong></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Lead</span><strong>Discuss delivery / routing</strong></a></div></div></section></div>',1)]))}const m=a(i,[["render",r]]);export{u as __pageData,m as default};
